return $input.all()
  .map(item => item.json.classroomLinks || [])
  .flat()
  .filter(url => url && url.includes("classroom.google.com"))
  .map(url => {
    return {
      json: {
        ...$input.first().json,
        url: url 
      }
    };
});

return $input.all().map(item => {

  const content =
    (item.json.html || "") +
    " " +
    (item.json.text || "");

  const allLinks = [
    ...content.matchAll(/https?:\/\/[^\s"'<>]+/g)
  ].map(m => m[0]);

  let cleaned = [];

  for (let link of allLinks) {

    try {

      const decoded = decodeURIComponent(link);

      // Google redirect links
      const match = decoded.match(
        /continue=(https:\/\/classroom\.google\.com[^&"]*)/
      );

      if (match) {

        const real = match[1];

        // Keep FULL assignment URLs
        if (
          real.includes("/c/") &&
          (
            real.includes("/a/") ||
            real.includes("/details")
          )
        ) {
          cleaned.push(real);
        }

        continue;
      }

      // Direct Classroom links
      if (
        link.startsWith("https://classroom.google.com")
      ) {
        cleaned.push(link);
      }

    } catch (e) {}

  }

  cleaned = [...new Set(cleaned)];

  return {
    json: {
      ...item.json,
      classroomLinks: cleaned
    }
  };

});

