 return $input.all().map(item => {

  const subject = item.json.Subject || "";
  const from = item.json.From || "";

  const assignmentName =
    (subject.match(/"([^"]+)"/) || [])[1] || "";

  const professor =
    (from.match(/"?(.+?)\s*\(Classroom\)/) || [])[1] || "";

  const receivedDate = new Date(
    Number(item.json.internalDate)
  ).toLocaleDateString("en-GB");

  return {
    json: {
      ...item.json,
      assignmentName,
      professor,
      receivedDate
    }
  };
});

 return $input.all().map(item => {
  const snippet =
    (item.json.snippet || "").toLowerCase();

  let dueDate = "";

  if (snippet.includes("due today")) {
    dueDate = new Date().toLocaleDateString("en-GB");
  }
  else if (snippet.includes("due tomorrow")) {
    const d = new Date();
    d.setDate(d.getDate() + 1);

    dueDate = d.toLocaleDateString("en-GB");
  }
  else {
    const match =
      snippet.match(/due\s+([a-z]{3}\s+\d{1,2})/i);

    if (match) {
      dueDate = match[1];
    }
  }

  return {
    json: {
      ...item.json,
      dueDate
    }
  };
});
